  transform: translate(-100%);
  }
}
@keyframes block-fall  {
  0%  {
  transform: translateY(-0.5em) rotate(3deg);
  opacity: 1;
  } 30%  {
  transform: translateY(0px) rotate(-4deg);
  opacity: 1;
  } 50%  {
  transform: translateY(-0.1em) rotate(0.5deg);
  opacity: 1;
  } 65%  {
  transform: translateY(0px) rotate(0deg);
