  transform: translateY(0px) rotate(0deg);
  opacity: 1;
  } 100%  {
  transform: translateY(0px) rotate(0deg);
  opacity: 1;
  }
}
@keyframes letter-jump  {
  0%  {
  transform: translateY(0px) scale(1);
  } 50%  {
  transform: translateY(-20px) scale(1.1);
  } 100%  {
  transform: translateY(0px) scale(1);
  }
}
@keyframes mapboxgl-user-location-dot-pulse  {
  0%  {
  opacity: 1;
  transform: scale(1);
